export const RARITY_CONFIG: Record<RarityCategory, { label: string; color: string; bg: string }> = {
  Common:       { label: 'Common',     color: '#646b73', bg: 'rgba(100,107,115,0.15)' },
  Uncommon:     { label: 'Uncommon',   color: '#187450', bg: 'rgba(24,116,80,0.15)' },
  Rare:         { label: 'Rare',       color: '#235f9b', bg: 'rgba(35,95,155,0.15)' },
  'Ultra Rare': { label: 'Ultra Rare', color: '#6750a4', bg: 'rgba(103,80,164,0.15)' },
  Legendary:    { label: 'Legendary',  color: '#b58a2a', bg: 'rgba(181,138,42,0.15)' },
}

export function getColorBySlug(slug: string): PorscheColor | undefined {
  return COLORS.find(c => c.slug === slug)
}

export function searchColors(query: string): PorscheColor[] {
  const q = query.toLowerCase()
  return COLORS.filter(c =>
    c.name.toLowerCase().includes(q) ||
    c.family.toLowerCase().includes(q) ||
    c.rarityCategory.toLowerCase().includes(q)
  )
}

export function colorImagePath(color: PorscheColor): string | null {
  if (!color.imageFile) return null
  if (color.imageFile.endsWith('.png')) return `/rennbow-car-cutouts/${color.imageFile}`
  return `/rennbow-color-images/${color.imageFile}`
}

export const FAMILIES = [...new Set(COLORS.map(c => c.family))].sort()
